Array.prototype.myMap = function (callbackFn, thisArg) {
  if (this == null) throw new TypeError('Array.prototype.myMap called on null/undefined');
  if (typeof callbackFn !== 'function') throw new TypeError(String(callbackFn) + ' is not a function');

  const O = Object(this);
  const len = O.length >>> 0; // snapshot length once
  const out = new Array(len);

  for (let k = 0; k < len; k++) {
    if (Object.prototype.hasOwnProperty.call(O, k)) {
      out[k] = callbackFn.call(thisArg, O[k], k, O);
    }
    // else: hole stays hole in out
  }

  return out;
};
